from collections import defaultdict

def dfs(cur, d):
    if cur == 0:
        return 1
    if d == 0:
        return 0
    if (cur, d) in memo:
        return memo[(cur, d)]
    ans = 0
    for i in range(1, 10):
        if cur >= i:
            ans += dfs(cur - i, d - 1)
    memo[(cur, d)] = ans
    return ans

l, r, k = map(int, input().split())
memo = defaultdict(int)
print(dfs(r, k) - dfs(l - 1, k) % 998244353)
